{
  "mode": "io",
  "tests": [
    {
      "name": "basic_case",
      "input": "1 2 3",
      "output": "6",
      "notes": "Basic addition of three integers."
    },
    {
      "name": "negative_numbers",
      "input": "-1 -2 -3",
      "output": "-6",
      "notes": "Testing addition with negative integers."
    },
    {
      "name": "zero_case",
      "input": "0 0 0",
      "output": "0",
      "notes": "Edge case with all zeros."
    },
    {
      "name": "large_numbers",
      "input": "1000000 2000000 3000000",
      "output": "6000000",
      "notes": "Testing with large integers."
    },
    {
      "name": "mixed_numbers",
      "input": "-1 0 1",
      "output": "0",
      "notes": "Testing with a mix of negative, zero, and positive."
    },
    {
      "name": "single_number",
      "input": "42",
      "output": "42",
      "notes": "Edge case with a single integer."
    },
    {
      "name": "two_numbers",
      "input": "5 10",
      "output": "15",
      "notes": "Testing with two integers."
    },
    {
      "name": "large_negative_numbers",
      "input": "-1000000 -2000000 -3000000",
      "output": "-6000000",
      "notes": "Testing with large negative integers."
    }
  ],
  "assumptions": "Input will always be valid integers.",
  "notes": "Ensure to handle both positive and negative integers correctly."
}
